using UnityEngine;

/// <summary>O valor de uma variável bool é igual a "expectedValue".</summary>
[System.Serializable]
public class Condition_BoolVariable : NpcCondition
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir, é tratada como tendo o valor por omissão (false).")]
    public string variableName;

    public bool expectedValue = true;

    public override bool Evaluate(NpcController npc)
    {
        return GameVariableUtil.GetBool(npc, scope, variableName) == expectedValue;
    }
}

/// <summary>Compara o valor de uma variável int com "value".</summary>
[System.Serializable]
public class Condition_IntVariable : NpcCondition
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir, é tratada como tendo o valor por omissão (0).")]
    public string variableName;

    public Comparison comparison = Comparison.Equal;
    public int value;

    public override bool Evaluate(NpcController npc)
    {
        int actual = GameVariableUtil.GetInt(npc, scope, variableName);
        return NpcConditionUtil.Compare(actual, comparison, value);
    }
}

/// <summary>Compara o valor de uma variável float com "value".</summary>
[System.Serializable]
public class Condition_FloatVariable : NpcCondition
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir, é tratada como tendo o valor por omissão (0).")]
    public string variableName;

    public Comparison comparison = Comparison.Equal;
    public float value;

    public override bool Evaluate(NpcController npc)
    {
        float actual = GameVariableUtil.GetFloat(npc, scope, variableName);
        return NpcConditionUtil.CompareFloat(actual, comparison, value);
    }
}

/// <summary>Compara o valor de uma variável de texto com "value" (igual ou diferente).</summary>
[System.Serializable]
public class Condition_StringVariable : NpcCondition
{
    [Tooltip("Onde a variável vive: Global (GameVariables, partilhada por todo o jogo) ou Local (só deste NPC).")]
    public VariableScope scope = VariableScope.Global;

    [Tooltip("Nome da variável. Se não existir, é tratada como tendo o valor por omissão (\"\").")]
    public string variableName;

    [Tooltip("true = a condição cumpre-se quando a variável É IGUAL a 'value'; false = quando é DIFERENTE.")]
    public bool mustEqual = true;

    public string value;

    public override bool Evaluate(NpcController npc)
    {
        string actual = GameVariableUtil.GetString(npc, scope, variableName);
        bool equal = actual == value;
        return equal == mustEqual;
    }
}
